    pop() {
        """Removes and returns the top item from the stack. Returns undefined if the stack is empty."""
        if (!this.isEmpty()) {
            return this.items.pop();
        }
        return undefined;
    }

    peek() {
        """Returns the top item of the stack without removing it. Returns undefined if the stack is empty."""
        if (!this.isEmpty()) {
