import heapq

class Heap:
    def __init__(self, is_min_heap=True):
        self.heap = []
        self.is_min_heap = is_min_heap

    def push(self, item):
        if self.is_min_heap:
            heapq.heappush(self.heap, item)
        else:
            # For a max-heap, store negative values to simulate max-heap behavior with heapq (which is a min-heap implementation)
            heapq.heappush(self.heap, -item)

    def pop(self):
        if not self.heap:
            return None
        if self.is_min_heap:
            return heapq.heappop(self.heap)
        else:
            return -heapq.heappop(self.heap)

    def peek(self):
        if not self.heap:
            return None
        if self.is_min_heap:
            return self.heap[0]
        else:
            return -self.heap[0]

    def __len__(self):
        return len(self.heap)

    def is_empty(self):
        return len(self.heap) == 0

