    private final PriorityQueue<Integer> heap;

    public Heap(boolean isMinHeap) {
        if (isMinHeap) {
            this.heap = new PriorityQueue<>();
        } else {
            this.heap = new PriorityQueue<>(Collections.reverseOrder());
        }
    }

    public void push(int item) {
        heap.offer(item);
    }

    public Integer pop() {
        return heap.isEmpty() ? null : heap.poll();
    }

    public Integer peek() {
        return heap.isEmpty() ? null : heap.peek();
    }

    public int size() {
        return heap.size();
    }

    public boolean isEmpty() {
        return heap.isEmpty();
    }
}

