function solveGraphProblem(graphRepresentation) {
    // graphRepresentation can be an adjacency list (Map or Object of Arrays/Sets)
    // or an adjacency matrix.

    // Example: Adjacency list representation
    // const graph = new Map([
    //     [0, [1, 2]],
    //     [1, [0, 3]],
    //     [2, [0]],
    //     [3, [1]]
    // ]);

    const numNodes = graphRepresentation.size; // or infer from input
    const visited = new Set(); // or an array for integer nodes

    // --- DFS Approach ---
    function dfs(node) {
        visited.add(node);
        // Process node here
        const neighbors = graphRepresentation.get(node) || [];
        for (const neighbor of neighbors) {
            if (!visited.has(neighbor)) {
                dfs(neighbor);
            }
        }
    }

    // --- BFS Approach ---
    function bfs(startNode) {
        const queue = [startNode];
        visited.add(startNode);

        while (queue.length > 0) {
            const currentNode = queue.shift();
            // Process node here
            const neighbors = graphRepresentation.get(currentNode) || [];
            for (const neighbor of neighbors) {
