function solveIntervals(intervals) {
    if (!intervals || intervals.length === 0) {
        return [];
    }

    // 1. Sort intervals based on their start times.
    intervals.sort((a, b) => a[0] - b[0]);

    const mergedIntervals = [];
    let currentInterval = intervals[0];

    for (let i = 1; i < intervals.length; i++) {
        const nextInterval = intervals[i];

        // 2. Check for overlap.
        // If the current interval's end is greater than or equal to the next interval's start,
        // there's an overlap.
        if (currentInterval[1] >= nextInterval[0]) {
            // 3. Merge overlapping intervals.
            // The new end is the maximum of the current and next interval's ends.
            currentInterval[1] = Math.max(currentInterval[1], nextInterval[1]);
        } else {
            // 4. No overlap, add the current merged interval to the result and start a new one.
            mergedIntervals.push(currentInterval);
            currentInterval = nextInterval;
        }
    }

    // 5. Add the last processed interval.
    mergedIntervals.push(currentInterval);

    return mergedIntervals;
}

