public static int[][] solveIntervals(int[][] intervals) {
    if (intervals == null || intervals.length == 0) {
        return new int[0][0];
    }

    // 1. Sort intervals based on their start times.
    Arrays.sort(intervals, Comparator.comparingInt(a -> a[0]));

    List<int[]> mergedIntervals = new ArrayList<>();
    int[] currentInterval = intervals[0].clone();

    for (int i = 1; i < intervals.length; i++) {
        int[] nextInterval = intervals[i];

        // 2. Check for overlap.
        if (currentInterval[1] >= nextInterval[0]) {
            // 3. Merge overlapping intervals.
            currentInterval[1] = Math.max(currentInterval[1], nextInterval[1]);
        } else {
            // 4. No overlap, add current and start a new interval.
            mergedIntervals.add(currentInterval);
            currentInterval = nextInterval.clone();
        }
    }

    // 5. Add the last processed interval.
    mergedIntervals.add(currentInterval);

    return mergedIntervals.toArray(new int[mergedIntervals.size()][]);
}

