      int height = i == heights.length ? 0 : heights[i];
      while (!stack.isEmpty() && height < heights[stack.peek()]) {
        int h = heights[stack.pop()];
        int w = stack.isEmpty() ? i : i - stack.peek() - 1;
        maxArea = Math.max(maxArea, h * w);
      }
      stack.push(i);
    }
    return maxArea;
  }
}

