      }
      if (nums[mid] == nums[mid + 1]) {
        low = mid + 2;
      } else {
        high = mid;
      }
    }
    return nums[low];
  }
}

class Solution {
  public Node connect(Node root) {
    if (root == null) {
      return null;
    }
    Node leftmost = root;
    while (leftmost.left != null) {
      Node head = leftmost;
      while (head != null) {
        head.left.next = head.right;
        if (head.next != null) {
          head.right.next = head.next.left;
        }
        head = head.next;
      }
      leftmost = leftmost.left;
    }
    return root;
  }
}

class Solution {
  public ListNode reverseList(ListNode head) {
    ListNode prev = null;
    ListNode curr = head;
    while (curr != null) {
      ListNode nextTemp = curr.next;
      curr.next = prev;
      prev = curr;
      curr = nextTemp;
    }
    return prev;
  }
}

class Solution {
  public ListNode mergeKLists(ListNode[] lists) {
    PriorityQueue<ListNode> queue = new PriorityQueue<>((a, b) -> a.val - b.val);
    for (ListNode list : lists) {
      if (list != null) {
        queue.offer(list);
      }
    }
    ListNode dummy = new ListNode(0);
    ListNode curr = dummy;
    while (!queue.isEmpty()) {
      ListNode node = queue.poll();
      curr.next = node;
      curr = curr.next;
      if (node.next != null) {
        queue.offer(node.next);
      }
    }
    return dummy.next;
  }
}

class Solution {
  public boolean hasCycle(ListNode head) {
    Set<ListNode> set = new HashSet<>();
    while (head != null) {
      if (set.contains(head)) {
        return true;
      }
      set.add(head);
      head = head.next;
    }
    return false;
  }
}

class Solution {
  public ListNode removeNthFromEnd(ListNode head, int n) {
    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode first = dummy;
    ListNode second = dummy;
    for (int i = 0; i <= n; i++) {
      first = first.next;
    }
    while (first != null) {
      first = first.next;
      second = second.next;
    }
    second.next = second.next.next;
    return dummy.next;
  }
}

class Solution {
  class Node {
    int key;
    int value;
    Node prev;
    Node next;
    public Node(int key, int value) {
      this.key = key;
      this.value = value;
    }
  }
  public LRUCache(int capacity) {
    this.capacity = capacity;
    cache = new HashMap<>();
    head = new Node(0, 0);
    tail = new Node(0, 0);
    head.next = tail;
    tail.prev = head;
  }
  public int get(int key) {
    if (cache.containsKey(key)) {
      Node node = cache.get(key);
      remove(node);
      add(node);
      return node.value;
    }
    return -1;
  }
  public void put(int key, int value) {
    if (cache.containsKey(key)) {
      remove(cache.get(key));
    }
    Node node = new Node(key, value);
    add(node);
    cache.put(key, node);
    if (cache.size() > capacity) {
      Node lru = head.next;
      remove(lru);
      cache.remove(lru.key);
    }
  }
  private void remove(Node node) {
    Node prev = node.prev;
    Node next = node.next;
    prev.next = next;
    next.prev = prev;
  }
  private void add(Node node) {
    Node prev = tail.prev;
    prev.next = node;
    tail.prev = node;
    node.prev = prev;
    node.next = tail;
  }
}

class Solution {
  public boolean isValid(ListNode head) {
    // Initialize two pointers, slow and fast
    ListNode slow = head;
    ListNode fast = head;

    // Traverse the list using the two pointers
    while (fast != null && fast.next != null) {
      slow = slow.next;
      fast = fast.next.next;
    }

    // Validate the list based on the problem requirements
    // For example, check if the list is a palindrome
    ListNode current = slow;
    ListNode prev = null;
    while (current != null) {
      ListNode nextTemp = current.next;
      current.next = prev;
      prev = current;
      current = nextTemp;
    }

    // Compare the first half and the reversed second half
    ListNode first = head;
    ListNode second = prev;
    while (second != null) {
      if (first.val != second.val) {
        return false;
      }
      first = first.next;
      second = second.next;
    }
    return true;
  }
}

class Solution {
  public List<Integer> inorderTraversal(TreeNode root) {
    List<Integer> result = new ArrayList<>();
    traverse(root, result);
    return result;
  }

  private void traverse(TreeNode node, List<Integer> result) {
    if (node == null) return;
    traverse(node.left, result);
    result.add(node.val);
    traverse(node.right, result);
  }
}

class Solution {
  public TreeNode constructTree(int[] preorder, int[] inorder) {
    return constructTree(preorder, 0, preorder.length - 1, inorder, 0, inorder.length - 1);
  }

  private TreeNode constructTree(int[] preorder, int preStart, int preEnd, int[] inorder, int inStart, int inEnd) {
    if (preStart > preEnd) return null;
    TreeNode root = new TreeNode(preorder[preStart]);
    int index = findIndex(inorder, inStart, inEnd, root.val);
    root.left = constructTree(preorder, preStart + 1, preStart + index - inStart, inorder, inStart, index - 1);
    root.right = constructTree(preorder, preStart + index - inStart + 1, preEnd, inorder, index + 1, inEnd);
    return root;
  }

  private int findIndex(int[] array, int start, int end, int target) {
    for (int i = start; i <= end; i++) {
      if (array[i] == target) return i;
    }
    return -1;
  }
}

class Solution {
  public boolean isValidBST(TreeNode root) {
    return isValidBST(root, Long.MIN_VALUE, Long.MAX_VALUE);
  }

  private boolean isValidBST(TreeNode node, long minVal, long maxVal) {
    if (node == null) return true;
    if (node.val <= minVal || node.val >= maxVal) return false;
    return isValidBST(node.left, minVal, node.val) && isValidBST(node.right, node.val, maxVal);
  }
}

class Solution {
  public String serialize(TreeNode root) {
    StringBuilder sb = new StringBuilder();
    serialize(root, sb);
    return sb.toString();
  }

  private void serialize(TreeNode node, StringBuilder sb) {
    if (node == null) {
      sb.append("#,");
      return;
    }
    sb.append(node.val + ",");
    serialize(node.left, sb);
    serialize(node.right, sb);
  }

  public TreeNode deserialize(String data) {
    String[] nodes = data.split(",");
    int[] index = new int[] { 0 };
    return deserialize(nodes, index);
  }

  private TreeNode deserialize(String[] nodes, int[] index) {
    if (index[0] >= nodes.length || nodes[index[0]].equals("#")) {
      index[0]++;
      return null;
    }
    TreeNode node = new TreeNode(Integer.parseInt(nodes[index[0]++]));
    node.left = deserialize(nodes, index);
    node.right = deserialize(nodes, index);
    return node;
  }
}

class Solution {
  public int maxDepth(TreeNode root) {
    if (root == null) return 0;
    return 1 + Math.max(maxDepth(root.left), maxDepth(root.right));
  }
}

class Solution {
  // Example: Invert Binary Tree
  public TreeNode invertTree(TreeNode root) {
    if (root == null) return null;
    // Swap left and right subtrees
    TreeNode temp = root.left;
    root.left = invertTree(root.right);
    root.right = invertTree(temp);
    return root;
  }

  // Example: Lowest Common Ancestor of a Binary Search Tree
  public TreeNode lowestCommonAncestor(TreeNode root, TreeNode p, TreeNode q) {
    if (root == null) return null;
    if (root.val > p.val && root.val > q.val) {
      return lowestCommonAncestor(root.left, p, q);
    } else if (root.val < p.val && root.val < q.val) {
      return lowestCommonAncestor(root.right, p, q);
    } else {
      return root;
    }
  }
}

class Solution {
  class TrieNode {
    TrieNode[] children = new TrieNode[26];
    boolean isEndOfWord;

    public TrieNode() {}
  }

  public void insert(TrieNode root, String word) {
    TrieNode node = root;
    for (char ch : word.toCharArray()) {
      int index = ch - 'a';
      if (node.children[index] == null) {
        node.children[index] = new TrieNode();
      }
      node = node.children[index];
    }
    node.isEndOfWord = true;
  }

  public boolean search(TrieNode root, String word) {
    TrieNode node = root;
    for (char ch : word.toCharArray()) {
      int index = ch - 'a';
      if (node.children[index] == null) {
        return false;
      }
      node = node.children[index];
    }
    return node.isEndOfWord;
  }

  public void delete(TrieNode root, String word) {
    delete(root, word, 0);
  }

  private boolean delete(TrieNode node, String word, int index) {
    if (index == word.length()) {
      if (!node.isEndOfWord) {
        return false;
      }
      node.isEndOfWord = false;
      return node.children == null || isEmpty(node);
    }
    int chIndex = word.charAt(index) - 'a';
    if (node.children[chIndex] == null) {
      return false;
    }
    boolean shouldDeleteCurrentNode = delete(node.children[chIndex], word, index + 1);
    if (shouldDeleteCurrentNode) {
      node.children[chIndex] = null;
      return isEmpty(node);
    }
    return false;
  }

  private boolean isEmpty(TrieNode node) {
    for (TrieNode child : node.children) {
      if (child != null) {
        return false;
      }
    }
    return true;
  }
}

class Solution {
  class TrieNode {
    TrieNode[] children = new TrieNode[26];
    String word;

    public TrieNode() {}
  }

  public List<String> findWords(char[][] board, String[] words) {
    TrieNode root = new TrieNode();
    for (String word : words) {
      TrieNode node = root;
      for (char ch : word.toCharArray()) {
        int index = ch - 'a';
        if (node.children[index] == null) {
          node.children[index] = new TrieNode();
        }
        node = node.children[index];
      }
      node.word = word;
    }

    List<String> result = new ArrayList<>();
    boolean[][] visited = new boolean[board.length][board[0].length];
    for (int i = 0; i < board.length; i++) {
      for (int j = 0; j < board[0].length; j++) {
        dfs(board, i, j, root, result, visited);
      }
    }
    return result;
  }

  private void dfs(char[][] board, int i, int j, TrieNode node, List<String> result, boolean[][] visited) {
    if (i < 0 || i >= board.length || j < 0 || j >= board[0].length || visited[i][j] || node.children[board[i][j] - 'a'] == null) {
      return;
    }
    visited[i][j] = true;
    node = node.children[board[i][j] - 'a'];
    if (node.word != null) {
      result.add(node.word);
      node.word = null;
    }
    dfs(board, i - 1, j, node, result, visited);
    dfs(board, i + 1, j, node, result, visited);
    dfs(board, i, j - 1, node, result, visited);
    dfs(board, i, j + 1, node, result, visited);
    visited[i][j] = false;
  }
}

class Solution {
  public int findKthLargest(int[] nums, int k) {
    // Create a min heap to store the k largest elements
    PriorityQueue<Integer> minHeap = new PriorityQueue<>();

    // Iterate through the array
    for (int num : nums) {
      // Add the current element to the heap
      minHeap.add(num);

      // If the heap size exceeds k, remove the smallest element
      if (minHeap.size() > k) {
        minHeap.poll();
      }
    }

    // The kth largest element is the smallest element in the heap
    return minHeap.peek();
  }
}

class Solution {
  public double findMedianFromDataStream(int num) {
    // Create a max heap to store the smaller half of the numbers
    PriorityQueue<Integer> maxHeap = new PriorityQueue<>((a, b) -> b - a);

    // Create a min heap to store the larger half of the numbers
    PriorityQueue<Integer> minHeap = new PriorityQueue<>();

    // Add the current number to the appropriate heap
    if (maxHeap.isEmpty() || num <= maxHeap.peek()) {
      maxHeap.add(num);
    } else {
      minHeap.add(num);
    }

    // Balance the heaps to ensure the size difference is at most 1
    if (maxHeap.size() > minHeap.size() + 1) {
      minHeap.add(maxHeap.poll());
    } else if (minHeap.size() > maxHeap.size()) {
      maxHeap.add(minHeap.poll());
    }

    // Calculate the median
    if (maxHeap.size() == minHeap.size()) {
      return (maxHeap.peek() + minHeap.peek()) / 2.0;
    } else {
      return (double) maxHeap.peek();
    }
  }
}

class Solution {
  public int leastInterval(char[] tasks, int n) {
    // Create a frequency array to store the frequency of each task
    int[] freq = new int[26];
    for (char task : tasks) {
      freq[task - 'A']++;
    }

    // Create a max heap to store the tasks
    PriorityQueue<Integer> maxHeap = new PriorityQueue<>((a, b) -> b - a);
    for (int i = 0; i < 26; i++) {
      if (freq[i] > 0) {
        maxHeap.add(freq[i]);
      }
    }

    // Initialize the result and the current time
    int result = 0;
    int time = 0;

    // Process the tasks
    while (!maxHeap.isEmpty()) {
      // Dequeue the task with the highest frequency
      int freqTask = maxHeap.poll();

      // Increment the time
      time++;

      // Decrement the frequency of the task
      freqTask--;

      // If the task still has frequency, add it back to the heap
      if (freqTask > 0) {
        maxHeap.add(freqTask);
      }

      // If the heap is empty and the time is less than n, increment the time
      if (maxHeap.isEmpty() && time < n) {
        time++;
      }
    }

    // Return the result
    return result;
  }
}

class Solution {
    public void backtrack(int[] nums, int start, List<List<Integer>> result, List<Integer> tempList) {
        result.add(new ArrayList<>(tempList));
        for (int i = start; i < nums.length; i++) {
            // Add current element to the temporary list
            tempList.add(nums[i]);
            // Recur for the next element
            backtrack(nums, i + 1, result, tempList);
            // Remove the current element from the temporary list (backtrack)
            tempList.remove(tempList.size() - 1);
        }
    }

    public List<List<Integer>> subsets(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        backtrack(nums, 0, result, new ArrayList<>());
        return result;
    }
}

class Solution {
    public void backtrack(int[] candidates, int start, int target, List<List<Integer>> result, List<Integer> tempList, int remain) {
        if (remain < 0) return;
        else if (remain == 0) result.add(new ArrayList<>(tempList));
        else {
            for (int i = start; i < candidates.length; i++) {
                // Add current element to the temporary list
                tempList.add(candidates[i]);
                // Recur for the next element
                backtrack(candidates, i, target, result, tempList, remain - candidates[i]);
                // Remove the current element from the temporary list (backtrack)
                tempList.remove(tempList.size() - 1);
            }
        }
    }

    public List<List<Integer>> combinationSum(int[] candidates, int target) {
        List<List<Integer>> result = new ArrayList<>();
        backtrack(candidates, 0, target, result, new ArrayList<>(), target);
        return result;
    }
}

class Solution {
    public boolean exist(char[][] board, String word) {
        for (int i = 0; i < board.length; i++) {
            for (int j = 0; j < board[0].length; j++) {
                if (board[i][j] == word.charAt(0)) {
                    if (backtrack(board, i, j, word, 0)) return true;
                }
            }
        }
        return false;
    }

    private boolean backtrack(char[][] board, int i, int j, String word, int index) {
        if (index == word.length()) return true;
        if (i < 0 || i >= board.length || j < 0 || j >= board[0].length || word.charAt(index) != board[i][j]) return false;
        char temp = board[i][j];
        board[i][j] = '#';
        boolean found = backtrack(board, i + 1, j, word, index + 1) ||
                         backtrack(board, i - 1, j, word, index + 1) ||
                         backtrack(board, i, j + 1, word, index + 1) ||
                         backtrack(board, i, j - 1, word, index + 1);
        board[i][j] = temp;
        return found;
    }
}

class Solution {
    public List<List<String>> partition(String s) {
        List<List<String>> result = new ArrayList<>();
        backtrack(s, 0, result, new ArrayList<>());
        return result;
    }

    private void backtrack(String s, int start, List<List<String>> result, List<String> tempList) {
        if (start == s.length()) {
            result.add(new ArrayList<>(tempList));
        } else {
            for (int i = start; i < s.length(); i++) {
                if (isPalindrome(s, start, i)) {
                    // Add current substring to the temporary list
                    tempList.add(s.substring(start, i + 1));
                    // Recur for the next substring
                    backtrack(s, i + 1, result, tempList);
                    // Remove the current substring from the temporary list (backtrack)
                    tempList.remove(tempList.size() - 1);
                }
            }
        }
    }

    private boolean isPalindrome(String s, int left, int right) {
        while (left < right) {
            if (s.charAt(left++) != s.charAt(right--)) return false;
        }
        return true;
    }
}

class Solution {
  public int numIslands(char[][] grid) {
    if (grid == null || grid.length == 0) return 0;
    int count = 0;
    for (int i = 0; i < grid.length; i++) {
      for (int j = 0; j < grid[0].length; j++) {
        if (grid[i][j] == '1') {
          dfs(grid, i, j);
          count++;
        }
      }
    }
    return count;
  }

  private void dfs(char[][] grid, int i, int j) {
    if (i < 0 || j < 0 || i >= grid.length || j >= grid[0].length || grid[i][j] != '1') return;
    grid[i][j] = '0';
    dfs(grid, i - 1, j);
    dfs(grid, i + 1, j);
    dfs(grid, i, j - 1);
    dfs(grid, i, j + 1);
  }
}

class Solution {
  public Node cloneGraph(Node node) {
    if (node == null) return null;
    Map<Node, Node> map = new HashMap<>();
    return clone(node, map);
  }

  private Node clone(Node node, Map<Node, Node> map) {
    if (map.containsKey(node)) return map.get(node);
    Node clone = new Node(node.val);
    map.put(node, clone);
    for (Node neighbor : node.neighbors) {
      clone.neighbors.add(clone(neighbor, map));
    }
    return clone;
  }
}

class Solution {
  public int[] findOrder(int numCourses, int[][] prerequisites) {
    int[] indegree = new int[numCourses];
    List<Integer>[] graph = new List[numCourses];
    for (int[] edge : prerequisites) {
      indegree[edge[0]]++;
      graph[edge[1]].add(edge[0]);
    }
    Queue<Integer> queue = new LinkedList<>();
    for (int i = 0; i < numCourses; i++) {
      if (indegree[i] == 0) queue.add(i);
    }
    int[] order = new int[numCourses];
    int index = 0;
    while (!queue.isEmpty()) {
      int course = queue.poll();
      order[index++] = course;
      for (int neighbor : graph[course]) {
        indegree[neighbor]--;
        if (indegree[neighbor] == 0) queue.add(neighbor);
      }
    }
    return index == numCourses ? order : new int[0];
  }
}

class Solution {
  public boolean isBipartite(int[][] graph) {
    int[] color = new int[graph.length];
    for (int i = 0; i < graph.length; i++) {
      if (color[i] == 0) {
        if (!dfs(graph, color, i, 1)) return false;
      }
    }
    return true;
  }

  private boolean dfs(int[][] graph, int[] color, int node, int currColor) {
    color[node] = currColor;
    for (int neighbor : graph[node]) {
      if (color[neighbor] == currColor) return false;
      if (color[neighbor] == 0) {
        if (!dfs(graph, color, neighbor, -currColor)) return false;
      }
    }
    return true;
  }
}

class Solution {
  public int ladderLength(String beginWord, String endWord, List<String> wordList) {
    Set<String> wordSet = new HashSet<>(wordList);
    Queue<String> queue = new LinkedList<>();
    queue.add(beginWord);
    int length = 1;
    while (!queue.isEmpty()) {
      int size = queue.size();
      for (int i = 0; i < size; i++) {
        String word = queue.poll();
        if (word.equals(endWord)) return length;
        for (int j = 0; j < word.length(); j++) {
          for (char c = 'a'; c <= 'z'; c++) {
            String nextWord = word.substring(0, j) + c + word.substring(j + 1);
            if (wordSet.contains(nextWord)) {
              queue.add(nextWord);
              wordSet.remove(nextWord);
            }
          }
        }
      }
      length++;
    }
    return 0;
  }
}

class Solution {
  public int solve(int[] weights, int[] values, int capacity) {
    int[] dp = new int[capacity + 1];
    for (int i = 1; i <= capacity; i++) {
      for (int j = 0; j < weights.length; j++) {
        if (weights[j] <= i) {
          dp[i] = Math.max(dp[i], dp[i - weights[j]] + values[j]);
        }
      }
    }
    return dp[capacity];
  }
}

class Solution {
  public int solve(int[] nums) {
    int[] dp = new int[nums.length];
    dp[0] = 1;
    for (int i = 1; i < nums.length; i++) {
      dp[i] = 1;
      for (int j = 0; j < i; j++) {
        if (nums[i] > nums[j]) {
          dp[i] = Math.max(dp[i], dp[j] + 1);
        }
      }
    }
    int max = 0;
    for (int i = 0; i < dp.length; i++) {
      max = Math.max(max, dp[i]);
    }
    return max;
  }
}

class Solution {
  public String solve(String s) {
    int start = 0, end = 0;
    for (int i = 0; i < s.length(); i++) {
      int len1 = expandAroundCenter(s, i, i);
      int len2 = expandAroundCenter(s, i, i + 1);
      int len = Math.max(len1, len2);
      if (len > (end - start)) {
        start = i - (len - 1) / 2;
        end = i + len / 2;
      }
    }
    return s.substring(start, end + 1);
  }
  private int expandAroundCenter(String s, int left, int right) {
    while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
      left--;
      right++;
    }
    return right - left - 1;
  }
}

class Solution {
  public int solve(int[] nums) {
    int[] dp = new int[nums.length];
    dp[0] = nums[0];
    for (int i = 1; i < nums.length; i++) {
      dp[i] = Math.max(dp[i - 1] + nums[i], nums[i]);
    }
    int max = dp[0];
    for (int i = 1; i < dp.length; i++) {
      max = Math.max(max, dp[i]);
    }
    return max;
  }
}

class Solution {
  public int uniquePaths(int m, int n) {
    int[][] dp = new int[m][n];
    // Initialize the base cases
    for (int i = 0; i < m; i++) {
      dp[i][0] = 1;
    }
    for (int j = 0; j < n; j++) {
      dp[0][j] = 1;
    }
    // Fill in the rest of the table
    for (int i = 1; i < m; i++) {
      for (int j = 1; j < n; j++) {
        dp[i][j] = dp[i-1][j] + dp[i][j-1];
      }
    }
    return dp[m-1][n-1];
  }
}

class Solution {
  public int longestCommonSubsequence(String text1, String text2) {
    int m = text1.length();
    int n = text2.length();
    int[][] dp = new int[m+1][n+1];
    // Fill in the table
    for (int i = 1; i <= m; i++) {
      for (int j = 1; j <= n; j++) {
        if (text1.charAt(i-1) == text2.charAt(j-1)) {
          dp[i][j] = dp[i-1][j-1] + 1;
        } else {
          dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]);
        }
      }
    }
    return dp[m][n];
  }
}

class Solution {
  public int change(int amount, int[] coins) {
    int[] dp = new int[amount + 1];
    dp[0] = 1;
    // Fill in the table
    for (int coin : coins) {
      for (int i = coin; i <= amount; i++) {
        dp[i] += dp[i - coin];
      }
    }
    return dp[amount];
  }
}

class Solution {
  public int maxProfit(int[] prices) {
    int buy = Integer.MIN_VALUE;
    int sell = 0;
    int cooldown = 0;
    // Fill in the table
    for (int price : prices) {
      int newBuy = Math.max(buy, cooldown - price);
      int newSell = Math.max(sell, buy + price);
      int newCooldown = Math.max(cooldown, sell);
      buy = newBuy;
      sell = newSell;
      cooldown = newCooldown;
    }
    return sell;
  }
}

class Solution {
  public int maxSubArray(int[] nums) {
    int currentSum = nums[0];
    int maxSum = nums[0];
    for (int i = 1; i < nums.length; i++) {
      currentSum = Math.max(nums[i], currentSum + nums[i]);
      maxSum = Math.max(maxSum, currentSum);
    }
    return maxSum;
  }
}

class Solution {
  public boolean canJump(int[] nums) {
    int farthestReachable = 0;
    for (int i = 0; i < nums.length; i++) {
      if (i > farthestReachable) {
        return false;
      }
      farthestReachable = Math.max(farthestReachable, i + nums[i]);
    }
    return true;
  }
}

class Solution {
  public List<Integer> partitionLabels(String S, String[] wordDict) {
    int[] lastOccurrence = new int[26];
    for (int i = 0; i < S.length(); i++) {
      lastOccurrence[S.charAt(i) - 'a'] = i;
    }
    List<Integer> result = new ArrayList<>();
    int anchor = 0;
    int j = 0;
    for (int i = 0; i < S.length(); i++) {
      j = Math.max(j, lastOccurrence[S.charAt(i) - 'a']);
      if (i == j) {
        result.add(i - anchor + 1);
        anchor = i + 1;
      }
    }
    return result;
  }
}

class Solution {
  public int[][] merge(int[][] intervals) {
    // Sort intervals by start time
    Arrays.sort(intervals, (a, b) -> a[0] - b[0]);

    List<int[]> merged = new ArrayList<>();
    for (int[] interval : intervals) {
      // If the list of merged intervals is empty or if the current interval does not overlap with the previous, append it.
      if (merged.isEmpty() || merged.get(merged.size() - 1)[1] < interval[0]) {
        merged.add(interval);
      } else {
        // Otherwise, there is overlap, so we merge the current and previous intervals.
        merged.get(merged.size() - 1)[1] = Math.max(merged.get(merged.size() - 1)[1], interval[1]);
      }
    }

    return merged.toArray(new int[0][]);
  }
}

class Solution {
  public int eraseOverlapIntervals(int[][] intervals) {
    if (intervals.length == 0) return 0;

    // Sort intervals by end time
    Arrays.sort(intervals, (a, b) -> a[1] - b[1]);

    int count = 1;
    int end = intervals[0][1];
    for (int[] interval : intervals) {
      if (interval[0] >= end) {
        count++;
        end = interval[1];
      }
    }

    return intervals.length - count;
  }
}
